"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { validateCRP } from "@/lib/utils";

type AuthMode = "login" | "register" | "forgot";
type Role = "therapist" | "patient";

export default function LoginPage() {
  const [mode, setMode] = useState<AuthMode>("login");
  const [role, setRole] = useState<Role>("therapist");
  const [form, setForm] = useState({ name: "", email: "", pass: "", crp: "" });
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");
  const router = useRouter();
  const supabase = createClient();

  const upd =
    (k: keyof typeof form) =>
    (e: React.ChangeEvent<HTMLInputElement>) =>
      setForm((f) => ({ ...f, [k]: e.target.value }));

  const submit = async () => {
    setLoading(true);
    setErr("");

    if (!form.email.includes("@")) {
      setErr("Email inválido");
      setLoading(false);
      return;
    }

    if (mode === "register" && role === "therapist" && !validateCRP(form.crp)) {
      setErr("CRP inválido. Formato esperado: 06/98421");
      setLoading(false);
      return;
    }

    try {
      if (mode === "login") {
        const { error } = await supabase.auth.signInWithPassword({
          email: form.email,
          password: form.pass,
        });
        if (error) throw error;
        router.push(role === "patient" ? "/portal" : "/dashboard");
        return;
      }

      if (mode === "register") {
        const { data, error } = await supabase.auth.signUp({
          email: form.email,
          password: form.pass,
          options: {
            data: { name: form.name, role, crp: form.crp },
          },
        });
        if (error) throw error;

        if (data.user) {
          router.push("/dashboard/onboarding");
        }
        return;
      }

      const { error } = await supabase.auth.resetPasswordForEmail(form.email, {
        redirectTo: `${window.location.origin}/auth/callback?type=recovery`,
      });
      if (error) throw error;
      setErr("");
      alert("Email de recuperação enviado!");
      setMode("login");
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : "Erro desconhecido";
      setErr(translateAuthError(msg));
    } finally {
      setLoading(false);
    }
  };

  const signInWithGoogle = async () => {
    await supabase.auth.signInWithOAuth({
      provider: "google",
      options: { redirectTo: `${window.location.origin}/auth/callback` },
    });
  };

  const sendMagicLink = async () => {
    if (!form.email.includes("@")) {
      setErr("Informe seu email primeiro");
      return;
    }
    setLoading(true);
    const { error } = await supabase.auth.signInWithOtp({
      email: form.email,
      options: { emailRedirectTo: `${window.location.origin}/auth/callback` },
    });
    setLoading(false);
    if (error) setErr(error.message);
    else alert(`Magic link enviado para ${form.email}!`);
  };

  function translateAuthError(msg: string): string {
    if (msg.includes("Invalid login credentials")) return "Email ou senha incorretos";
    if (msg.includes("Email not confirmed")) return "Confirme seu email antes de entrar";
    if (msg.includes("User already registered")) return "Este email já está cadastrado";
    if (msg.includes("Password should be at least")) return "Senha deve ter pelo menos 6 caracteres";
    return msg;
  }

  return (
    <div className="min-h-screen bg-[var(--color-bg-base)] lg:grid lg:grid-cols-[1.3fr_1fr]">
      <section className="hidden border-r border-[var(--color-border-subtle)] px-12 py-16 lg:flex lg:flex-col lg:justify-center xl:px-20">
        <div className="mb-4 text-[52px] leading-none text-[var(--color-brand)]">Ψ</div>
        <h1 className="mb-5 whitespace-pre-line font-[family-name:var(--font-display)] text-[64px] font-light leading-[1.03] tracking-tight text-[var(--color-text-primary)]">
          {mode === "login" ? "Bem-vindo\nde volta." : "Comece\nhoje mesmo."}
        </h1>
        <p className="max-w-[520px] text-[17px] leading-8 text-[var(--color-text-secondary)]">
          A plataforma que cuida de quem cuida: IA clínica, Telegram bot e prontuário LGPD em um só lugar.
        </p>

        <div className="mt-10 flex flex-col gap-4">
          {[
            { icon: "✦", text: "IA com Claude, GPT-4o, Gemini" },
            { icon: "✦", text: "Telegram Bot automático" },
            { icon: "✦", text: "KPIs e prontuário LGPD" },
          ].map((item) => (
            <div key={item.text} className="flex items-center gap-3 text-[15px] text-[var(--color-text-secondary)]">
              <span className="text-[var(--color-brand)]">{item.icon}</span>
              {item.text}
            </div>
          ))}
        </div>
      </section>

      <section className="flex w-full flex-col justify-center bg-[var(--color-bg-elevated)] px-5 py-8 sm:px-8 lg:px-12 xl:px-16">
        <div className="mx-auto w-full max-w-[620px]">
          <div className="mb-6 flex gap-2 rounded-2xl border border-[var(--color-border-subtle)] bg-[var(--color-surface)] p-1">
            {(
              [
                { v: "therapist", l: "Psicanalista" },
                { v: "patient", l: "Paciente" },
              ] as const
            ).map((item) => {
              const active = role === item.v;
              return (
                <button
                  key={item.v}
                  type="button"
                  onClick={() => setRole(item.v)}
                  className={`flex-1 rounded-xl px-3 py-2.5 text-[13px] font-medium transition-colors ${
                    active
                      ? "border border-[rgba(82,183,136,.3)] bg-[var(--color-brand-subtle)] text-[var(--color-brand)]"
                      : "text-[var(--color-text-muted)] hover:text-[var(--color-text-secondary)]"
                  }`}
                >
                  {item.l}
                </button>
              );
            })}
          </div>

          <h2 className="mb-1 font-[family-name:var(--font-display)] text-[42px] font-light leading-none text-[var(--color-text-primary)]">
            {mode === "login"
              ? "Acessar conta"
              : mode === "register"
                ? "Criar conta grátis"
                : "Recuperar senha"}
          </h2>
          <p className="mb-6 text-[14px] text-[var(--color-text-muted)]">
            {role === "therapist" ? "Painel clínico completo" : "Sua jornada terapêutica começa aqui"}
          </p>

          {err && (
            <div className="mb-4 rounded-xl border border-[#f87171]/35 bg-[#f87171]/12 px-4 py-3 text-[13px] text-[#f87171]">
              {err}
            </div>
          )}

          <div className="flex flex-col gap-3.5">
            {mode === "register" && (
              <input
                name="name"
                className="w-full rounded-xl border border-[var(--color-border-strong)] bg-[var(--color-surface)] px-4 py-3 text-[14px] text-[var(--color-text-primary)] outline-none transition-colors placeholder:text-[var(--color-text-muted)] focus:border-[var(--color-brand)]"
                placeholder={role === "therapist" ? "Nome (Dr./Dra.)" : "Seu nome completo"}
                value={form.name}
                onChange={upd("name")}
                aria-label="Nome"
              />
            )}

            <input
              className="w-full rounded-xl border border-[var(--color-border-strong)] bg-[var(--color-surface)] px-4 py-3 text-[14px] text-[var(--color-text-primary)] outline-none transition-colors placeholder:text-[var(--color-text-muted)] focus:border-[var(--color-brand)]"
              placeholder="Email"
              type="email"
              value={form.email}
              onChange={upd("email")}
              aria-label="Email"
              autoComplete="email"
            />

            {mode !== "forgot" && (
              <input
                className="w-full rounded-xl border border-[var(--color-border-strong)] bg-[var(--color-surface)] px-4 py-3 text-[14px] text-[var(--color-text-primary)] outline-none transition-colors placeholder:text-[var(--color-text-muted)] focus:border-[var(--color-brand)]"
                placeholder="Senha"
                type="password"
                value={form.pass}
                onChange={upd("pass")}
                aria-label="Senha"
                autoComplete={mode === "login" ? "current-password" : "new-password"}
              />
            )}

            {mode === "register" && role === "therapist" && (
              <input
                className="w-full rounded-xl border border-[var(--color-border-strong)] bg-[var(--color-surface)] px-4 py-3 text-[14px] text-[var(--color-text-primary)] outline-none transition-colors placeholder:text-[var(--color-text-muted)] focus:border-[var(--color-brand)]"
                placeholder="CRP (ex: 06/98421)"
                value={form.crp}
                onChange={upd("crp")}
                aria-label="Número CRP"
              />
            )}
          </div>

          {mode === "login" && (
            <button
              type="button"
              onClick={() => setMode("forgot")}
              className="mt-2 self-end text-[12px] text-[var(--color-text-muted)] transition-colors hover:text-[var(--color-text-secondary)]"
            >
              Esqueci a senha
            </button>
          )}

          <button
            type="button"
            onClick={submit}
            disabled={loading}
            aria-label={mode === "login" ? "Entrar" : mode === "register" ? "Criar conta" : "Enviar link"}
            className={`mt-5 flex items-center justify-center gap-2 rounded-xl px-5 py-3.5 text-[20px] font-semibold transition-colors ${
              loading
                ? "cursor-not-allowed border border-[var(--color-border-subtle)] bg-[var(--color-surface)] text-[var(--color-text-muted)]"
                : "bg-[var(--color-brand)] text-[#060E09] hover:bg-[var(--color-brand-hover)]"
            }`}
          >
            {loading
              ? "..."
              : mode === "login"
                ? "Entrar"
                : mode === "register"
                  ? "Criar conta"
                  : "Enviar link"}
          </button>

          <div className="my-4 flex items-center gap-3">
            <div className="h-px flex-1 bg-[var(--color-border-subtle)]" />
            <span className="text-[11px] text-[var(--color-text-muted)]">ou continue com</span>
            <div className="h-px flex-1 bg-[var(--color-border-subtle)]" />
          </div>

          <button
            type="button"
            onClick={signInWithGoogle}
            className="mb-2 flex w-full items-center justify-center gap-2 rounded-xl border border-[var(--color-border-strong)] bg-[var(--color-surface)] px-4 py-2.5 text-[13px] text-[var(--color-text-secondary)] transition-colors hover:border-[var(--color-border-strong)] hover:bg-[var(--color-surface-hover)] hover:text-[var(--color-text-primary)]"
          >
            <span className="font-bold">G</span> Continuar com Google
          </button>

          <button
            type="button"
            onClick={sendMagicLink}
            disabled={loading}
            className={`w-full rounded-xl border px-4 py-2.5 text-[13px] transition-colors ${
              loading
                ? "cursor-not-allowed border-[var(--color-border-subtle)] bg-[var(--color-surface)] text-[var(--color-text-muted)]"
                : "border-[var(--color-border-strong)] bg-[var(--color-surface)] text-[var(--color-text-secondary)] hover:bg-[var(--color-surface-hover)] hover:text-[var(--color-text-primary)]"
            }`}
          >
            Enviar magic link
          </button>

          <p className="mt-5 text-center text-[13px] text-[var(--color-text-muted)]">
            {mode === "login" ? "Ainda não tem conta?" : "Já possui conta?"}{" "}
            <button
              type="button"
              onClick={() => setMode(mode === "login" ? "register" : "login")}
              className="font-medium text-[var(--color-brand)] transition-colors hover:text-[var(--color-brand-hover)]"
            >
              {mode === "login" ? "Criar conta" : "Entrar"}
            </button>
          </p>
        </div>
      </section>
    </div>
  );
}
